// Output format constants
export const OUTPUT_FORMATS = {
  MARKDOWN: 'markdown',
  PLAIN: 'plain',
  NUMBERED: 'numbered',
  CHECKLIST: 'checklist'
};

// Format grocery list for copying to clipboard
export const formatForCopy = (list, format) => {
  switch (format) {
    case OUTPUT_FORMATS.PLAIN:
      return list.replace(/## /g, '').replace(/- /g, '');
    case OUTPUT_FORMATS.NUMBERED:
      let counter = 1;
      return list.replace(/- (.+)/g, (match, item) => `${counter++}. ${item}`);
    case OUTPUT_FORMATS.CHECKLIST:
      return list.replace(/- (.+)/g, '- [ ] $1');
    case OUTPUT_FORMATS.MARKDOWN:
    default:
      return list;
  }
};

// Format a single line for display
export const formatLine = (line, format, index) => {
  const commonStyle = {
    margin: '2px 0',
    fontSize: '12px',
    color: '#2c3e50'
  };

  // Handle different formats
  if (format === OUTPUT_FORMATS.MARKDOWN && line.startsWith('## ')) {
    return (
      <div key={index} style={{
        fontWeight: 'bold',
        margin: '12px 0 6px 0',
        fontSize: '14px',
        color: '#2c3e50'
      }}>
        {line.replace('## ', '')}
      </div>
    );
  }

  if (format === OUTPUT_FORMATS.MARKDOWN && line.startsWith('- ')) {
    return (
      <div key={index} style={{
        ...commonStyle,
        paddingLeft: '12px'
      }}>
        • {line.replace('- ', '')}
      </div>
    );
  }

  if (format === OUTPUT_FORMATS.NUMBERED && /^\d+\.\s/.test(line)) {
    return (
      <div key={index} style={{
        ...commonStyle,
        paddingLeft: '12px'
      }}>
        {line}
      </div>
    );
  }

  if (format === OUTPUT_FORMATS.CHECKLIST && line.startsWith('- [ ] ')) {
    return (
      <div key={index} style={{
        ...commonStyle,
        paddingLeft: '12px'
      }}>
        ☐ {line.replace('- [ ] ', '')}
      </div>
    );
  }

  if (format === OUTPUT_FORMATS.CHECKLIST && line.startsWith('## ')) {
    return (
      <div key={index} style={{
        fontWeight: 'bold',
        margin: '12px 0 6px 0',
        fontSize: '14px',
        color: '#2c3e50'
      }}>
        {line.replace('## ', '')}
      </div>
    );
  }

  // Handle regular lines
  if (line.trim()) {
    const isHeader = (format === OUTPUT_FORMATS.NUMBERED && !line.match(/^[\d\-•]/));
    const shouldBeBold = isHeader && format !== OUTPUT_FORMATS.PLAIN;

    return (
      <div key={index} style={{
        ...commonStyle,
        fontWeight: shouldBeBold ? 'bold' : 'normal',
        marginTop: isHeader ? '12px' : '2px',
        marginBottom: isHeader ? '6px' : '2px'
      }}>
        {line}
      </div>
    );
  }

  return null;
};

// Format entire grocery list for display
export const formatGroceryList = (text, format) => {
  const formattedText = formatForCopy(text, format);
  const lines = formattedText.split('\n');
  const formattedLines = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (line.trim() === '') continue;

    const formatted = formatLine(line, format, formattedLines.length);
    if (formatted) {
      formattedLines.push(formatted);
    }
  }

  return formattedLines;
};
